<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Snake</title>
<style>
  body{margin:0;background:#111;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{margin:0 5px;padding:5px 10px;font-size:16px;}
  #score{font-size:18px;margin-left:15px;}
  canvas{background:#222;border:2px solid #555;display:block;}
</style>
</head>
<body>
<canvas id="snake" width="400" height="400"></canvas>
<div id="controls">
  <button id="start">Start</button>
  <button id="pause">Pause</button>
  <button id="reset">Reset</button>
  <span id="score">Score: 0</span>
</div>

<script>
(() => {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');

  // Grid settings
  const w = 20; // cells horizontally
  const h = 20; // cells vertically
  const cellSize = canvas.width / w;

  let snakeArr = []; // array of {x,y}
  let dir = 'right'; // current direction
  let nextDir = dir; // queued direction
  let foodPos = null;
  let aliveFlag = true;
  let scoreVal = 0;
  let intervalId = null;

  const opposite = {'up':'down','down':'up','left':'right','right':'left'};

  function reset() {
    snakeArr = [];
    // start with length 3
    for (let i=2;i>=0;--i) snakeArr.push({x:i,y:0});
    dir = 'right';
    nextDir = dir;
    aliveFlag = true;
    scoreVal = 0;
    placeFood();
    draw();
    updateScore();
  }

  function tick() {
    if (!aliveFlag) return;
    // apply queued direction unless it's a reversal
    if (nextDir !== opposite[dir]) dir = nextDir;

    const head = snakeArr[0];
    let nx = head.x, ny = head.y;
    switch(dir){
      case 'up': ny--; break;
      case 'down': ny++; break;
      case 'left': nx--; break;
      case 'right': nx++; break;
    }

    // collision with walls
    if (nx<0||ny<0||nx>=w||ny>=h){ aliveFlag=false; draw(); return;}

    // collision with self
    for(let i=1;i<snakeArr.length;i++){
      if(snakeArr[i].x===nx && snakeArr[i].y===ny){
        aliveFlag=false; draw(); return;
      }
    }

    const ate = foodPos && foodPos[0]===nx && foodPos[1]===ny;

    // add new head
    snakeArr.unshift({x:nx,y:ny});
    if (!ate) {
      snakeArr.pop(); // remove tail
    } else {
      scoreVal++;
      placeFood();
    }
    draw();
    updateScore();
  }

  function setDir(d){
    nextDir = d;
  }

  function setFood(x,y){ foodPos=[x,y]; draw();}
  function snake(){ return snakeArr.map(p=>[p.x,p.y]);}
  function food(){ return foodPos;}
  function alive(){ return aliveFlag;}
  function score(){ return scoreVal;}

  function placeFood(){
    const free = [];
    for(let i=0;i<w;i++)for(let j=0;j<h;j++){
      if(!snakeArr.some(p=>p.x===i&&p.y===j)) free.push([i,j]);
    }
    if(free.length===0){ aliveFlag=false; draw(); return;}
    const [fx,fy] = free[Math.floor(Math.random()*free.length)];
    foodPos=[fx,fy];
  }

  function draw(){
    ctx.fillStyle='#222';
    ctx.fillRect(0,0,canvas.width,canvas.height);
    // draw snake
    for(let i=0;i<snakeArr.length;i++){
      const p=snakeArr[i];
      ctx.fillStyle=i===0?'lime':'green';
      ctx.fillRect(p.x*cellSize,p.y*cellSize,cellSize-1,cellSize-1);
    }
    // draw food
    if(foodPos){
      ctx.fillStyle='red';
      ctx.beginPath();
      const [fx,fy]=foodPos;
      ctx.arc((fx+0.5)*cellSize,(fy+0.5)*cellSize,cellSize*0.4,0,Math.PI*2);
      ctx.fill();
    }
  }

  function updateScore(){ scoreEl.textContent='Score: '+scoreVal;}

  // UI
  document.getElementById('start').addEventListener('click',()=>{
    if(intervalId===null) intervalId=setInterval(tick,200);
  });
  document.getElementById('pause').addEventListener('click',()=>{
    clearInterval(intervalId); intervalId=null;
  });
  document.getElementById('reset').addEventListener('click',()=>{clearInterval(intervalId);intervalId=null; reset();});

  // keyboard
  window.addEventListener('keydown',(e)=>{
    const keyMap={'ArrowUp':'up','ArrowDown':'down','ArrowLeft':'left','ArrowRight':'right'};
    if(keyMap[e.key]) setDir(keyMap[e.key]);
  });

  // expose API
  window.game = {w,h,reset,tick,setDir,setFood,snake,food,alive,score};

  reset();
})();
</script>
</body>
</html>
